module top_module(Out, In, Reset, Clk, Load, obf_Increment);parameter SIZE=4;
input obf_Increment;
input [SIZE-1:0]In;
input Reset, Clk, Load;
output [SIZE-1:0]Out;
reg [SIZE-1:0]Out;

always @ (posedge Clk or negedge Reset)
	if(!Reset)
		Out = 0;
	else 
	 begin
     if (obf_Increment) 
	   	Out = Out +1;
	 if(Load)
			Out = In;
      end
endmodule
